div.script:
(function(){
  /* Scroll reveal */
  var io = new IntersectionObserver(function(entries){
    entries.forEach(function(e){
      if(e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }
    });
  }, {threshold: 0.07});
  document.querySelectorAll('.rv,.rv-l,.rv-r').forEach(function(el){ io.observe(el); });

  /* Sticky navbar */
  var nav  = document.getElementById('apNav');
  var hero = document.querySelector('.cd-hero');
  var isSticky = false;
  function onScroll(){
    var scrolled = window.scrollY > 80;
    if(scrolled && !isSticky){
      nav.classList.add('sticky');
      document.body.appendChild(nav);
      isSticky = true;
    } else if(!scrolled && isSticky){
      nav.classList.remove('sticky');
      hero.insertBefore(nav, hero.firstChild);
      isSticky = false;
    }
  }
  window.addEventListener('scroll', onScroll, {passive: true});

  /* Mobile hamburger */
  document.getElementById('apHam').addEventListener('click', function(){
    document.getElementById('apMob').classList.toggle('open');
  });
})();
